B.KI=new A.b_("pda_ab_single",'PDA: "ab"','Build a PDA that accepts exactly the string "ab".\nUse a stack push on "a" and pop it when you see "b".\nTransition format: input,stackTop|stackPush  (use \u2205 for empty/no-op).',"      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (1000.0, 360.0)\n      n2 is accepted\n      n0 to n1 = a,\u2205|X\n      n1 to n2 = b,X|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aV,null,B.Uq,0.2,"pda")
B.UF=new A.cv("pda_ab_single")
B.K8=new A.b_("pda_balanced_parens","Balanced Parentheses",'Build a PDA over {(, )} that accepts strings with balanced parentheses (e.g. "(()())" accepted, "(()" rejected).\nPush a marker on every "(" and pop it on every ")".',"      pda mode\n      n0 = A\n      n1 = B\n      n0 = (480.0, 360.0)\n      n1 = (820.0, 360.0)\n      n0 is accepted\n      n0 to n0 = (,\u2205|X\n      n0 to n1 = ),X|\u2205\n      n1 to n1 = ),X|\u2205\n      n1 to n0 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aV,null,B.UF,0.4,"pda")
B.UG=new A.cv("pda_balanced_parens")
B.K1=new A.b_("pda_anbn","a\u207fb\u207f","Build a PDA that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1): the same number of a's followed by the same number of b's.\nClassic context-free language \u2014 not recognisable by any DFA!","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aV,null,B.UG,0.6,"pda")
