B.K3=new A.b_("tm_identity","TM: Accept All (Trivial)","Build the simplest possible Turing machine: one that accepts every input by halting immediately.\nA single state that is both start and accept will do it. TM transition format: readSymbol writeSymbol Direction (e.g. aBR = read a, write B, move Right).","      tm mode\n      n0 = A\n      A = (600.0, 360.0)\n      A is accepted\n      to A angle = -1.0000, 0.0000\n    ",B.aQ,null,B.Uo,0.25,"tm")
