B.KB=new A.b_("tm_unary_increment","TM: Unary Increment","Build a TM over {1} that accepts strings of the form 1\u207f for any n \u2265 0. The machine should scan past all 1s and accept when it hits blank. This checks you can drive the head right and accept on blank.","      tm mode\n      n0 = A\n      n1 = B\n      A = (460.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to A = 11R\n      A to B = \u2205\u2205S\n      l0(11R) loop angle = -1.5708\n      to A angle = -1.0000, 0.0000\n    ",B.aQ,null,B.UI,0.75,"tm")
