B.Ky=new A.b_("tm_binary_increment","TM: Binary Increment","Build a TM over {0,1} that accepts any binary string (treat the tape as a binary number and verify the head can scan it). The machine must scan from left to right over 0s and 1s and halt-accept on blank.","      tm mode\n      n0 = A\n      n1 = B\n      A = (480.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to A = 00R\n      A to A = 11R\n      A to B = \u2205\u2205S\n      l0(00R) loop angle = -1.5708\n      l1(11R) loop angle = -0.8000\n      to A angle = -1.0000, 0.0000\n    ",B.aQ,null,B.Bw,0.45,"tm")
