B.Kk=new A.b_("tm_ww","TM: ww (Doubled Word)",'Build a TM that accepts strings of the form ww over {a, b}: a string that consists of some word w repeated exactly twice (e.g. "abab", "aabbaa bb"). This is a classic non-context-free language.',"      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 180.0)\n      B = (660.0, 180.0)\n      C = (1060.0, 180.0)\n      D = (1060.0, 540.0)\n      E = (660.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to D = bXL\n      C to C = aaR\n      C to C = bbR\n      C to E = aXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.8000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.8000\n      l7(aaL) loop angle = 1.5708\n      l8(bbL) loop angle = 0.8000\n      l10(aaL) loop angle = 1.5708\n      l11(bbL) loop angle = 0.8000\n      aXR curve = 60.0\n      bXR curve = -60.0\n      bXL curve = 60.0\n      aXL curve = -60.0\n      XXR_D curve = 80.0\n      XXR_E curve = -80.0\n      to A angle = -1.0000, 0.0000\n    ",B.aQ,null,B.Uk,0.25,"tm")
B.Kt=new A.b_("tm_anbncn","TM: a\u207fb\u207fc\u207f","Build a TM that accepts strings of the form a\u207fb\u207fc\u207f (n \u2265 1).\nThis language is not context-free \u2014 no PDA can recognise it \u2014 but a TM can! Cross off one a, one b, and one c per pass.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (580.0, 200.0)\n      C = (900.0, 200.0)\n      D = (900.0, 540.0)\n      E = (580.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      B to B = aaR\n      B to B = XXR\n      B to C = bXR\n      C to C = bbR\n      C to C = XXR\n      C to D = cXL\n      D to D = bbL\n      D to D = ccL\n      D to D = XXL\n      D to E = aaL\n      E to E = aaL\n      E to E = bbL\n      E to E = ccL\n      E to E = XXL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(XXR) loop angle = -0.8000\n      l4(bbR) loop angle = -1.5708\n      l5(XXR) loop angle = -0.8000\n      l7(bbL) loop angle = 1.5708\n      l8(ccL) loop angle = 0.8000\n      l9(XXL) loop angle = 2.3000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.8000\n      l13(ccL) loop angle = 2.3000\n      l14(XXL) loop angle = 3.1000\n      aXR curve = 70.0\n      bXR curve = 70.0\n      cXL curve = 70.0\n      aaL_E curve = 60.0\n      XXR_E curve = 60.0\n      to A angle = -1.0000, 0.0000\n    ",B.aQ,null,B.Bw,0.55,"tm")
